const stytch = require('stytch');
const fs = require('fs');
const path = require('path');

async function run() {
  const client = new stytch.B2BClient({
    project_id: process.env.STYTCH_PROJECT_ID,
    secret: process.env.STYTCH_SECRET,
  });

  const timestamp = Date.now();
  const orgSlug = `acme-scim-org-${timestamp}`;

  try {
    console.log(`Creating organization: ${orgSlug}...`);
    const orgResponse = await client.organizations.create({
      organization_name: 'Acme SCIM Org',
      organization_slug: orgSlug,
    });

    const organization_id = orgResponse.organization.organization_id;
    console.log(`Organization created: ${organization_id}`);

    console.log('Creating SCIM connection...');
    const scimResponse = await client.scim.connection.create({
      organization_id: organization_id,
      display_name: 'Acme SCIM Connection',
      identity_provider: 'okta',
    });

    const connection = scimResponse.connection;
    const output = {
      organization_id: organization_id,
      connection_id: connection.connection_id,
      base_url: connection.base_url,
      bearer_token: connection.bearer_token,
    };

    const outputPath = '/home/user/app/scim_output.json';
    fs.writeFileSync(outputPath, JSON.stringify(output, null, 2));
    console.log(`Output written to ${outputPath}`);
  } catch (error) {
    console.error('Error in setup_scim:', error);
    process.exit(1);
  }
}

run();

